// ── Time Window Check (9 AM – 8 PM Eastern) ──────────────────────────────
const now = new Date();
const etFormatter = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/New_York',
  hour: 'numeric',
  hour12: false
});
const etHour = parseInt(etFormatter.format(now), 10);

if (etHour < 9 || etHour >= 20) {
  return [];
}

return [{ json: { etHour, timestamp: now.toISOString(), active: true } }];

// ── Load Crawl State (uses n8n workflow static data — persists across runs) ──
const staticData = $getWorkflowStaticData('global');

const state = {
  processedProfileUrls: staticData.processedProfileUrls || [],
  processedThreadUrls: staticData.processedThreadUrls || [],
  processedNameCompanyKeys: staticData.processedNameCompanyKeys || [],
  googleSheetId: staticData.googleSheetId || $env.VISTAGE_SHEET_ID || '',
  totalDiscoveredAllTime: staticData.totalDiscoveredAllTime || 0,
  lastRunAt: staticData.lastRunAt || null,
  lastRunNewCount: staticData.lastRunNewCount || 0,
  runHistory: staticData.runHistory || []
};

console.log(`State loaded. Total discovered all-time: ${state.totalDiscoveredAllTime}. Processed profiles: ${state.processedProfileUrls.length}.`);

return [{ json: { state, quota: 50, newThisRun: 0 } }];

// ── Extract CSRF Token & Cookies from Login Page ────────────────────────
const response = $input.first().json;
const html = typeof response.body === 'string' ? response.body : JSON.stringify(response.body);

const csrfMatch = html.match(/name=["'](?:_csrf|csrfToken|authenticity_token|__RequestVerificationToken)["']\s+(?:value|content)=["']([^"']+)["']/i)
                || html.match(/["']csrfToken["']\s*:\s*["']([^"']+)["']/i)
                || html.match(/data-csrf=["']([^"']+)["']/i);
const csrfToken = csrfMatch ? csrfMatch[1] : '';

const headers = response.headers || {};
let cookies = '';
if (headers['set-cookie']) {
  const cookieArr = Array.isArray(headers['set-cookie']) ? headers['set-cookie'] : [headers['set-cookie']];
  cookies = cookieArr.map(c => c.split(';')[0]).join('; ');
}

const state = $('Load Crawl State').first().json.state;
return [{ json: { csrfToken, cookies, state, quota: 50, newThisRun: 0 } }];

// ── Extract Auth Session Cookie ──────────────────────────────────────────
const response = $input.first().json;
const headers = response.headers || {};

let sessionCookie = '';
if (headers['set-cookie']) {
  const cookieArr = Array.isArray(headers['set-cookie']) ? headers['set-cookie'] : [headers['set-cookie']];
  sessionCookie = cookieArr.map(c => c.split(';')[0]).join('; ');
}

const prevCookies = $('Extract CSRF Token').first().json.cookies || '';
const allCookies = [prevCookies, sessionCookie].filter(Boolean).join('; ');
const html = typeof response.body === 'string' ? response.body : '';
const loggedIn = html.includes('dashboard') || html.includes('community') || response.statusCode === 302;
const state = $('Extract CSRF Token').first().json.state;

console.log(`Login attempt — logged in: ${loggedIn}, status: ${response.statusCode}`);
return [{ json: { sessionCookie: allCookies, loggedIn, state, quota: 50, newThisRun: 0 } }];

// ── Parse Profile URLs from All Network Member Pages ─────────────────────
const items = $input.all();
const state = $('Extract Session Cookie').first().json.state;
const sessionCookie = $('Extract Session Cookie').first().json.sessionCookie;

const alreadyProcessed = new Set(state.processedProfileUrls || []);
const ownProfile = 'jperez48';
const profilePattern = /https:\/\/myvistage\.com\/profile\/\?[^\/]+\/$/;

const allUrls = new Set();

for (const item of items) {
  const html = typeof item.json.body === 'string' ? item.json.body : '';
  const matches = [...html.matchAll(/href="(\/profile\/\?[^"]+\/)"/gi)];
  for (const m of matches) {
    const url = 'https://myvistage.com' + m[1];
    if (!url.includes(ownProfile) &&
        !url.includes('/calendar') && !url.includes('/friends') &&
        !url.includes('/notifications') && !url.includes('/messages') &&
        profilePattern.test(url) &&
        !alreadyProcessed.has(url)) {
      allUrls.add(url);
    }
  }
}

const newUrls = [...allUrls].slice(0, 50);
console.log(`Found ${allUrls.size} new profile URLs across all networks. Processing ${newUrls.length}.`);

if (newUrls.length === 0) return [];

return newUrls.map(url => ({ json: { profileUrl: url, sessionCookie, state } }));

// ── Extract Profile Data (PeepSo / myvistage.com structure) ──────────────
const response = $input.first().json;
const prevData = $('Profile Loop').first().json;
const html = typeof response.body === 'string' ? response.body : '';

// Name: from page title or span.notranslate
const nameFromTitle = (html.match(/<title>(?:\(\d+\)\s*)?([^|<-]+)/i) || [])[1]?.trim() || '';
const nameFromSpan = (html.match(/<span[^>]*class="notranslate"[^>]*>([^<]+)<\/span>/i) || [])[1]?.trim() || '';
const fullName = nameFromSpan || nameFromTitle || 'Unknown';

// Title + Company: from p.profile_user_title (format: Title<br>Company)
const titleCompanyMatch = html.match(/<p[^>]*class="[^"]*profile_user_title[^"]*"[^>]*>(.*?)<\/p>/is);
let jobTitle = '', company = '';
if (titleCompanyMatch) {
  const parts = titleCompanyMatch[1].split(/<br\s*\/?>/i).map(s => s.replace(/<[^>]+>/g, '').trim());
  jobTitle = parts[0] || '';
  company = parts[1] || '';
}

// Extract structured sections (About me, Company, Networks)
const sectionData = {};
const sectionMatches = [...html.matchAll(/<[^>]*class="[^"]*ps-profile__header[^"]*vistage-profile-header[^"]*"[^>]*>([^<]+)<\/[^>]+>([\s\S]*?)(?=<[^>]*class="[^"]*ps-profile__header|$)/gi)];
for (const m of sectionMatches) {
  const key = m[1].trim();
  const content = m[2].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  sectionData[key] = content;
}

const companySection = sectionData['Company'] || '';
const aboutSection = sectionData['About me'] || '';
const networksSection = sectionData['Networks'] || '';

const industry = (companySection.match(/Industry:\s*([^\n]+)/) || [])[1]?.trim() || '';
const role = (companySection.match(/Role:\s*([^\n]+)/) || [])[1]?.trim() || '';
const bizType = (companySection.match(/Business Type:\s*([^\n]+)/) || [])[1]?.trim() || '';
const locMatch = companySection.match(/([A-Za-z ]+,\s*[A-Za-z ]+\d{5})/);
const location = locMatch ? locMatch[1].trim() : '';
const bio = aboutSection.replace(/Biography:\s*/,'').replace(/Business Description:.*/s,'').trim().substring(0, 200);
const bizDesc = (aboutSection.match(/Business Description:\s*([^\n]+)/) || [])[1]?.trim() || '';
const networks = networksSection.split(/\n|,/).map(s => s.trim()).filter(s => s.includes('Network')).join(', ');

// Dedup check by name+company
const state = prevData.state || {};
const nameKey = `${fullName.toLowerCase()}|${company.toLowerCase()}`;
const alreadyByName = (state.processedNameCompanyKeys || []).includes(nameKey);

if (alreadyByName || fullName === 'Unknown') {
  console.log(`Skipping ${fullName} — already processed or unknown`);
  return [];
}

return [{
  json: {
    profileUrl: prevData.profileUrl,
    fullName, jobTitle, company, industry, role, bizType, location, bio, bizDesc, networks,
    state: prevData.state,
    nameKey
  }
}];

