// ── Parse AI Score & Format Row for Google Sheets ───────────────────────
const aiResponse = $input.first().json;
const profile = $('Extract Profile Data').first().json;

let ai = {};
try {
  const text = aiResponse?.content?.[0]?.text || '{}';
  ai = JSON.parse(text.replace(/```json|```/g, '').trim());
} catch(e) {
  ai = { crmFitScore: 5, erpFitScore: 5, aiFitScore: 5, opportunityTier: 'WARM', relevantTopics: '', summary: '', buyingSignals: '' };
}

const today = new Date().toLocaleDateString('en-US', { timeZone: 'America/New_York' });

return [{
  json: {
    dateDiscovered: today,
    fullName: profile.fullName,
    jobTitle: profile.jobTitle,
    company: profile.company,
    email: '',
    phone: '',
    profileUrl: profile.profileUrl,
    groups: profile.networks,
    industry: profile.industry,
    crmFitScore: parseInt(ai.crmFitScore) || 5,
    erpFitScore: parseInt(ai.erpFitScore) || 5,
    aiFitScore: parseInt(ai.aiFitScore) || 5,
    opportunityTier: ai.opportunityTier || 'WARM',
    relevantTopics: ai.relevantTopics || '',
    summaryOfDiscussions: ai.summary || '',
    buyingSignals: ai.buyingSignals || '',
    sourceThreadUrl: 'https://myvistage.com/groups/?artificial-intelligence-network/members/',
    lastChecked: new Date().toISOString(),
    status: 'New',
    _profileUrl: profile.profileUrl,
    _nameKey: profile.nameKey,
    _state: profile.state
  }
}];

// ── Save State Back to n8n Static Data ───────────────────────────────────
const items = $input.all();
if (!items.length) return [{ json: { saved: false } }];

const staticData = $getWorkflowStaticData('global');

// Collect all newly processed profiles from this run
const newProfileUrls = items.map(i => i.json._profileUrl).filter(Boolean);
const newNameKeys = items.map(i => i.json._nameKey).filter(Boolean);

const existingProfiles = new Set(staticData.processedProfileUrls || []);
const existingKeys = new Set(staticData.processedNameCompanyKeys || []);

newProfileUrls.forEach(u => existingProfiles.add(u));
newNameKeys.forEach(k => existingKeys.add(k));

staticData.processedProfileUrls = [...existingProfiles];
staticData.processedNameCompanyKeys = [...existingKeys];
staticData.totalDiscoveredAllTime = (staticData.totalDiscoveredAllTime || 0) + items.length;
staticData.lastRunAt = new Date().toISOString();
staticData.lastRunNewCount = items.length;
staticData.runHistory = [
  ...((staticData.runHistory || []).slice(-49)),
  { runAt: new Date().toISOString(), newCount: items.length, networksVisited: ['AI Network', 'Entrepreneurs Network', 'Manufacturing Network'] }
];

console.log(`State saved. This run: ${items.length}. All-time: ${staticData.totalDiscoveredAllTime}.`);
return [{ json: { saved: true, thisRun: items.length, totalAllTime: staticData.totalDiscoveredAllTime } }];
